def build_linked_list(values):
    head = None
    tail = None

    for value in values:
        new_node = Node(value)
        if head is None:
            head = new_node
            tail = new_node
        else:
            tail.next = new_node
            tail = new_node

    return head


def to_list(head):
    result = []
    current = head
    while current is not None:
        result.append(current.data)
        current = current.next
    return result


